import{_ as t,C as s,o,c as i,a0 as r,E as n}from"./chunks/framework.dpbUfbgZ.js";const d="/assets/solution-components.BgFAhrND.png",g=JSON.parse('{"title":"Components","description":"","frontmatter":{},"headers":[],"relativePath":"components.md","filePath":"components.md","lastUpdated":1774511953000}'),c={name:"components.md"};function l(p,e,m,h,u,v){const a=s("PageCards");return o(),i("div",null,[e[0]||(e[0]=r('<h1 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h1><p>The CE-RISE solution combines interoperable data models with modular software components and reusable implementation resources.</p><h2 id="data-models" tabindex="-1">Data models <a class="header-anchor" href="#data-models" aria-label="Permalink to &quot;Data models&quot;">​</a></h2><p>The solution builds on a layered digital passport data model architecture, designed to support shared structures, specialization, and interoperability across use cases.</p><div class="ce-rise-grid"><div class="ce-rise-card"><h3>Core Layers</h3><p>The foundation of every Digital Passport, providing essential identity and metadata management infrastructure.</p></div><div class="ce-rise-card"><h3>Value-Added Information Layers</h3><p>The rich, domain-specific information that creates value for different stakeholders throughout the product or material lifecycle.</p></div><div class="ce-rise-card"><h3>Cross-Cutting Utility Layers</h3><p>Reusable components that support data quality and reliability across all other layers.</p></div></div><p><img src="https://ce-rise-models.codeberg.page/dp-architecture/dpp-architecture.png" alt="Layered data model architecture"></p><div class="info custom-block"><p class="custom-block-title">Take-home message</p><p>The CE-RISE data models provide a layered and interoperable structure that supports reuse, specialization, and consistent digital passport information across use cases.</p></div><hr><h2 id="software-components" tabindex="-1">Software components <a class="header-anchor" href="#software-components" aria-label="Permalink to &quot;Software components&quot;">​</a></h2><p>The software architecture is based on modular service types that can be combined and extended according to need.</p><div class="ce-rise-grid"><div class="ce-rise-card"><h3>Hexagonal Core</h3><p>The generic model-aware core service of the solution. It resolves model artifacts, validates payloads against the relevant models, and provides the common API used to create, query, and validate digital passport records across different use cases. It is designed to support multiple consumers through inbound interfaces, including support for authentication and idempotency, while keeping orchestration and validation logic independent from model-specific applications.</p></div><div class="ce-rise-card"><h3>Data Backend</h3><p>In production settings, DPP storage and data maintenance are expected to be handled by dedicated, verifiable, and trustworthy specialized systems. CE-RISE has also developed specialized integration interfaces with state-of-the-art commercial solutions for DPP storage. Within the CE-RISE solution, the current data-backend component provides a practical solution for testing and development through standard database integration. It stores and retrieves digital passport records without taking on model-specific validation, enrichment, or workflow logic.</p></div><div class="ce-rise-card"><h3>Application Services</h3><p>Specialized application services for particular models, record sections, or business workflows. They collect information, enrich existing records, or compute derived data, and can link the system to live data and siloed data storage, including ERP systems, data spaces, and digital twin representations. They then rely on Hex Core Service to validate and integrate those results into the overall system.</p></div></div> The CE-RISE solution also includes documentation, APIs, web and command line clients, repositories, demonstrators, and archived resources that help users understand, evaluate, and reuse the system in practice. <div style="height:1rem;"></div>` <p><img src="'+d+'" alt="CE-RISE Solution Software Components"></p><div class="info custom-block"><p class="custom-block-title">Take-home message</p><p>The CE-RISE software components are modular by design, so core services and specialized services can be combined, replaced, and extended as needed.</p></div><hr>',17)),n(a,{items:[{title:"Home",link:"/"},{title:"References",link:"/references"}]})])}const b=t(c,[["render",l]]);export{g as __pageData,b as default};
